class ThreadedQueue:
    """Bounded queue with blocking put/ get_batch and explicit *close()* semantics."""

    __slots__ = ("_closed", "_items", "_lock", "_max", "_not_empty", "_not_full")

    def __init__(self, max_size: int) -> None:
        self._max: int = max_size
        self._items: deque[ThreadedItem] = deque()
        self._lock = threading.Lock()
        self._not_full = threading.Condition(self._lock)
        self._not_empty = threading.Condition(self._lock)
        self._closed = False

    # ---------------------------------------------------------------- put()
    def put(self, item: ThreadedItem, timeout: float | None = None) -> bool:
        """Block until queue accepts *item* or is closed.  Returns *False* if closed."""
        with self._not_full:
            if self._closed:
                return False
            start = time.monotonic()
            while len(self._items) >= self._max and not self._closed:
                if timeout is not None:
                    remaining = timeout - (time.monotonic() - start)
                    if remaining <= 0:
                        return False
                    self._not_full.wait(remaining)
                else:
                    self._not_full.wait()
            if self._closed:
                return False
            self._items.append(item)
            self._not_empty.notify()
            return True

    # ------------------------------------------------------------ get_batch()
    def get_batch(self, size: int, timeout: float | None = None) -> List[ThreadedItem]:
        """Return up to *size* items.  Blocks until \u22651 item present or queue closed/timeout."""
        with self._not_empty:
            start = time.monotonic()
            while not self._items and not self._closed:
                if timeout is not None:
                    remaining = timeout - (time.monotonic() - start)
                    if remaining <= 0:
                        return []
                    self._not_empty.wait(remaining)
                else:
                    self._not_empty.wait()
            batch: List[ThreadedItem] = []
            while self._items and len(batch) < size:
                batch.append(self._items.popleft())
            if batch:
                self._not_full.notify_all()
            return batch

    # ---------------------------------------------------------------- close()
    def close(self) -> None:
        with self._lock:
            self._closed = True
            self._not_empty.notify_all()
            self._not_full.notify_all()

def _handle_text_element(self, element, out_doc, current_list, page_height):
    cap_text = element.text

    prov = ProvenanceItem(
        page_no=element.page_no,
        charspan=(0, len(cap_text)),
        bbox=element.cluster.bbox.to_bottom_left_origin(page_height),
    )
    label = element.label
    if label == DocItemLabel.LIST_ITEM:
        if current_list is None:
            current_list = out_doc.add_group(label=GroupLabel.LIST, name="list")

        # TODO: Infer if this is a numbered or a bullet list item
        new_item = out_doc.add_list_item(
            text=cap_text, enumerated=False, prov=prov, parent=current_list
        )
        self.list_item_processor.process_list_item(new_item)

    elif label == DocItemLabel.SECTION_HEADER:
        current_list = None

        new_item = out_doc.add_heading(text=cap_text, prov=prov)
    elif label == DocItemLabel.FORMULA:
        current_list = None

        new_item = out_doc.add_text(
            label=DocItemLabel.FORMULA, text="", orig=cap_text, prov=prov
        )
    else:
        current_list = None

        content_layer = ContentLayer.BODY
        if element.label in [DocItemLabel.PAGE_HEADER, DocItemLabel.PAGE_FOOTER]:
            content_layer = ContentLayer.FURNITURE

        new_item = out_doc.add_text(
            label=element.label,
            text=cap_text,
            prov=prov,
            content_layer=content_layer,
        )
    return new_item, current_list

def __init__(
    self,
    path_or_stream: Union[BytesIO, Path],
    format: InputFormat,
    backend: Type[AbstractDocumentBackend],
    backend_options: Optional[BackendOptions] = None,
    filename: Optional[str] = None,
    limits: Optional[DocumentLimits] = None,
) -> None:
    super().__init__(
        file="",
        document_hash="",
        format=InputFormat.PDF,
        backend_options=backend_options,
    )  # initialize with dummy values
    self.limits = limits or DocumentLimits()
    self.format = format

    try:
        if isinstance(path_or_stream, Path):
            self.file = path_or_stream
            self.filesize = path_or_stream.stat().st_size
            if self.filesize > self.limits.max_file_size:
                self.valid = False
            else:
                self.document_hash = create_file_hash(path_or_stream)
                self._init_doc(backend, path_or_stream)

        elif isinstance(path_or_stream, BytesIO):
            assert filename is not None, (
                "Can't construct InputDocument from stream without providing "
                "filename arg."
            )
            self.file = PurePath(filename)
            self.filesize = path_or_stream.getbuffer().nbytes

            if self.filesize > self.limits.max_file_size:
                self.valid = False
            else:
                self.document_hash = create_file_hash(path_or_stream)
                self._init_doc(backend, path_or_stream)
        else:
            raise RuntimeError(
                f"Unexpected type path_or_stream: {type(path_or_stream)}"
            )

        # For paginated backends, check if the maximum page count is exceeded.
        if self.valid and self._backend.is_valid():
            if self._backend.supports_pagination() and isinstance(
                self._backend, PaginatedDocumentBackend
            ):
                self.page_count = self._backend.page_count()
                if not self.page_count <= self.limits.max_num_pages:
                    self.valid = False
                elif self.page_count < self.limits.page_range[0]:
                    self.valid = False

    except (FileNotFoundError, OSError) as e:
        self.valid = False
        _log.exception(
            f"File {self.file.name} not found or cannot be opened.", exc_info=e
        )
        # raise
    except RuntimeError as e:
        self.valid = False
        _log.exception(
            "An unexpected error occurred while opening the document "
            f"{self.file.name}",
            exc_info=e,
        )

def _guess_format(self, obj: Union[Path, DocumentStream]) -> Optional[InputFormat]:
    content = b""  # empty binary blob
    formats: list[InputFormat] = []

    if isinstance(obj, Path):
        mime = filetype.guess_mime(str(obj))
        if mime is None:
            ext = obj.suffix[1:]
            mime = _DocumentConversionInput._mime_from_extension(ext)
        if mime is None:  # must guess from
            with obj.open("rb") as f:
                content = f.read(1024)  # Read first 1KB
        if mime is not None and mime.lower() == "application/zip":
            mime_root = "application/vnd.openxmlformats-officedocument"
            suffix = obj.suffix.lower()
            if suffix == ".xlsx":
                mime = mime_root + ".spreadsheetml.sheet"
            elif suffix == ".docx":
                mime = mime_root + ".wordprocessingml.document"
            elif suffix == ".pptx":
                mime = mime_root + ".presentationml.presentation"
            else:
                office_mime = _DocumentConversionInput._detect_office_mime_from_zip(
                    obj
                )
                if office_mime is not None:
                    mime = office_mime

    elif isinstance(obj, DocumentStream):
        content = obj.stream.read(8192)
        obj.stream.seek(0)
        mime = filetype.guess_mime(content)
        if mime is None:
            ext = (
                obj.name.rsplit(".", 1)[-1]
                if ("." in obj.name and not obj.name.startswith("."))
                else ""
            )
            mime = _DocumentConversionInput._mime_from_extension(ext.lower())
        if mime is not None and mime.lower() == "application/zip":
            objname = obj.name.lower()
            mime_root = "application/vnd.openxmlformats-officedocument"
            if objname.endswith(".xlsx"):
                mime = mime_root + ".spreadsheetml.sheet"
            elif objname.endswith(".docx"):
                mime = mime_root + ".wordprocessingml.document"
            elif objname.endswith(".pptx"):
                mime = mime_root + ".presentationml.presentation"
            else:
                office_mime = _DocumentConversionInput._detect_office_mime_from_zip(
                    obj.stream
                )
                if office_mime is not None:
                    mime = office_mime

    if mime is not None and mime.lower() == "application/gzip":
        if detected_mime := _DocumentConversionInput._detect_mets_gbs(obj):
            mime = detected_mime

    mime = mime or _DocumentConversionInput._detect_html_xhtml(content)
    mime = mime or _DocumentConversionInput._detect_csv(content)
    mime = mime or "text/plain"
    formats = MimeTypeToFormat.get(mime, [])
    _log.info(f"detected formats: {formats}")

    if formats:
        if len(formats) == 1 and mime not in ("text/plain"):
            return formats[0]
        else:  # ambiguity in formats
            return _DocumentConversionInput._guess_from_content(
                content, mime, formats
            )
    else:
        return None

class AbstractDocumentBackend(ABC):
    @abstractmethod
    def __init__(
        self,
        in_doc: "InputDocument",
        path_or_stream: Union[BytesIO, Path],
        options: BaseBackendOptions = BaseBackendOptions(),
    ):
        self.file = in_doc.file
        self.path_or_stream = path_or_stream
        self.document_hash = in_doc.document_hash
        self.input_format = in_doc.format
        self.options = options

    @abstractmethod
    def is_valid(self) -> bool:
        pass

    @classmethod
    @abstractmethod
    def supports_pagination(cls) -> bool:
        pass

    def unload(self):
        if isinstance(self.path_or_stream, BytesIO):
            self.path_or_stream.close()

        self.path_or_stream = None

    @classmethod
    @abstractmethod
    def supported_formats(cls) -> set["InputFormat"]:
        pass


